PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?northCountryLabel WHERE {
  wd:Q15180 wdt:P47 ?northCountry .
  ?northCountry rdfs:label ?northCountryLabel .
  FILTER(LANG(?northCountryLabel) = "en")
  .
  VALUES ?northCountry {
    wd:Q26
  }
}
